import java.util.ArrayList;
import java.util.List;

public class CircularBuffer<T> {
    private final Object[] buffer;
    private final int capacity;
    private int writePos;
    private int readPos;
    private int count;

    public CircularBuffer(int capacity) {
        this.capacity = capacity;
        this.buffer = new Object[capacity];
        this.writePos = 0;
        this.readPos = 0;
        this.count = 0;
    }

    public void write(T item) {
        buffer[writePos] = item;
        if (count == capacity) {
            readPos = (readPos + 1) % capacity;
        } else {
            count++;
        }
        writePos = (writePos + 1) % capacity;
    }

    @SuppressWarnings("unchecked")
    public T read() {
        if (count == 0) throw new IllegalStateException("Buffer is empty");
        T item = (T) buffer[readPos];
        readPos = (readPos + 1) % capacity;
        count--;
        return item;
    }

    @SuppressWarnings("unchecked")
    public List<T> readAll() {
        List<T> result = new ArrayList<>(count);
        int pos = readPos;
        for (int i = 0; i < count; i++) {
            result.add((T) buffer[pos]);
            pos = (pos + 1) % capacity;
        }
        return result;
    }

    public boolean isEmpty() { return count == 0; }
    public boolean isFull() { return count == capacity; }
    public int size() { return count; }
}

import java.util.ArrayDeque;
import java.util.Deque;
import java.util.HashSet;
import java.util.Set;

public class SnakeGame {
    private final int width;
    private final int height;
    private final int[][] food;
    private int foodIndex;
    private int score;
    private boolean gameOver;
    private final Deque<int[]> snake;
    private final Set<String> snakeSet;

    public SnakeGame(int width, int height, int[][] food) {
        this.width = width;
        this.height = height;
        this.food = food;
        this.foodIndex = 0;
        this.score = 0;
        this.gameOver = false;
        snake = new ArrayDeque<>();
        snakeSet = new HashSet<>();
        snake.addFirst(new int[]{0, 0});
        snakeSet.add("0,0");
    }

    public int move(String direction) {
        if (gameOver) return -1;

        int[] head = snake.peekFirst();
        int newRow = head[0];
        int newCol = head[1];

        switch (direction) {
            case "U": newRow--; break;
            case "D": newRow++; break;
            case "L": newCol--; break;
            case "R": newCol++; break;
        }

        if (newRow < 0 || newRow >= height || newCol < 0 || newCol >= width) {
            gameOver = true;
            return -1;
        }

        boolean ateFood = foodIndex < food.length
                && food[foodIndex][0] == newRow
                && food[foodIndex][1] == newCol;

        if (!ateFood) {
            int[] tail = snake.pollLast();
            snakeSet.remove(tail[0] + "," + tail[1]);
        }

        String newKey = newRow + "," + newCol;
        if (snakeSet.contains(newKey)) {
            gameOver = true;
            return -1;
        }

        snake.addFirst(new int[]{newRow, newCol});
        snakeSet.add(newKey);

        if (ateFood) {
            score++;
            foodIndex++;
        }

        return score;
    }
}

