import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

public class UrlShortener {
    private static final String BASE62 = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ";
    private static final int CODE_LENGTH = 6;
    private static final long MAX_ID = (long) Math.pow(62, CODE_LENGTH);

    private final ConcurrentHashMap<String, String> urlToCode = new ConcurrentHashMap<>();
    private final ConcurrentHashMap<String, String> codeToUrl = new ConcurrentHashMap<>();
    private final AtomicLong counter = new AtomicLong(0);

    public String shorten(String longUrl) {
        String existing = urlToCode.get(longUrl);
        if (existing != null) return existing;

        String code;
        String finalCode;
        do {
            long id = counter.getAndIncrement();
            if (id >= MAX_ID) throw new RuntimeException("URL space exhausted");
            code = toBase62(id);
        } while (codeToUrl.putIfAbsent(code, longUrl) != null
                && !longUrl.equals(codeToUrl.get(code)));

        finalCode = code;
        urlToCode.putIfAbsent(longUrl, finalCode);
        return urlToCode.get(longUrl);
    }

    public String expand(String code) {
        String url = codeToUrl.get(code);
        if (url == null) throw new IllegalArgumentException("Code not found: " + code);
        return url;
    }

    private String toBase62(long id) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < CODE_LENGTH; i++) {
            sb.append(BASE62.charAt((int)(id % 62)));
            id /= 62;
        }
        return sb.reverse().toString();
    }

    public long fromBase62(String code) {
        long result = 0;
        for (char c : code.toCharArray()) {
            result = result * 62 + BASE62.indexOf(c);
        }
        return result;
    }
}

