import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.locks.ReentrantLock;

// 수정 버전 1: synchronized
public class BankAccountSynchronized {
    private int balance;

    public BankAccountSynchronized(int initialBalance) {
        this.balance = initialBalance;
    }

    public synchronized boolean withdraw(int amount) {
        if (balance >= amount) {
            balance -= amount;
            return true;
        }
        return false;
    }

    public synchronized void deposit(int amount) {
        balance += amount;
    }

    public synchronized int getBalance() { return balance; }
}

// 수정 버전 2: ReentrantLock
public class BankAccountLock {
    private int balance;
    private final ReentrantLock lock = new ReentrantLock();

    public BankAccountLock(int initialBalance) {
        this.balance = initialBalance;
    }

    public boolean withdraw(int amount) {
        lock.lock();
        try {
            if (balance >= amount) {
                balance -= amount;
                return true;
            }
            return false;
        } finally {
            lock.unlock();
        }
    }

    public void deposit(int amount) {
        lock.lock();
        try {
            balance += amount;
        } finally {
            lock.unlock();
        }
    }

    public int getBalance() {
        lock.lock();
        try { return balance; }
        finally { lock.unlock(); }
    }
}

// 수정 버전 3: AtomicInteger + CAS
public class BankAccountAtomic {
    private final AtomicInteger balance;

    public BankAccountAtomic(int initialBalance) {
        this.balance = new AtomicInteger(initialBalance);
    }

    public boolean withdraw(int amount) {
        while (true) {
            int current = balance.get();
            if (current < amount) return false;
            if (balance.compareAndSet(current, current - amount)) return true;
        }
    }

    public void deposit(int amount) {
        balance.addAndGet(amount);
    }

    public int getBalance() { return balance.get(); }
}

