import java.util.*;

public class AutocompleteSystem {
    private final TrieNode root;
    private static final int TOP_K = 3;

    private static class TrieNode {
        Map<Character, TrieNode> children = new HashMap<>();
        String word = null;
        int frequency = 0;
    }

    public AutocompleteSystem() {
        root = new TrieNode();
    }

    public void insert(String word, int frequency) {
        TrieNode node = root;
        for (char c : word.toCharArray()) {
            node.children.putIfAbsent(c, new TrieNode());
            node = node.children.get(c);
        }
        node.word = word;
        node.frequency = frequency;
    }

    public List<String> search(String prefix) {
        TrieNode node = root;
        for (char c : prefix.toCharArray()) {
            if (!node.children.containsKey(c)) return Collections.emptyList();
            node = node.children.get(c);
        }

        // minHeap: 낮은 빈도가 top → 크기 K 유지하며 최솟값 제거
        PriorityQueue<TrieNode> heap = new PriorityQueue<>((a, b) -> {
            if (a.frequency != b.frequency) return a.frequency - b.frequency;
            return b.word.compareTo(a.word); // 알파벳 역순 (min heap에서 제거 대상)
        });

        dfs(node, heap);

        List<String> result = new ArrayList<>();
        while (!heap.isEmpty()) result.add(0, heap.poll().word);
        return result;
    }

    private void dfs(TrieNode node, PriorityQueue<TrieNode> heap) {
        if (node.word != null) {
            heap.offer(node);
            if (heap.size() > TOP_K) heap.poll();
        }
        for (TrieNode child : node.children.values()) {
            dfs(child, heap);
        }
    }
}

