import java.util.Arrays;
import java.util.List;

public class BugFixes {

    // ===== Bug 1: NullPointerException =====
    // 원본 (버그): list.get(0).toUpperCase() — list가 null이면 NPE, 비어있으면 IOOBE
    String getFirstElement(List<String> list) {
        if (list == null || list.isEmpty()) {
            return null;
        }
        String first = list.get(0);
        return first != null ? first.toUpperCase() : null;
    }

    // ===== Bug 2: Off-by-One Error =====
    // 원본 (버그): i <= arr.length — i == arr.length에서 ArrayIndexOutOfBoundsException
    int sumArray(int[] arr) {
        if (arr == null) return 0;
        int sum = 0;
        for (int i = 0; i < arr.length; i++) { // <= → < 수정
            sum += arr[i];
        }
        return sum;
        // 또는: return Arrays.stream(arr).sum();
    }

    // ===== Bug 3: Integer Overflow =====
    // 원본 (버그): (long)(a + b) — a+b가 int로 먼저 계산되어 오버플로 후 long 캐스팅
    long twoSum(int a, int b) {
        return (long) a + b; // a를 먼저 long으로 승격 → 덧셈이 long 범위에서 수행
        // 또는: return Long.sum(a, b);
    }

    // ===== 보너스: Binary Search mid 계산 overflow =====
    int safeMid(int lo, int hi) {
        // Bug: return (lo + hi) / 2; // lo+hi가 int 범위 초과 가능
        return lo + (hi - lo) / 2; // 안전한 방법
        // 또는: return (lo + hi) >>> 1;
    }

    long safeMultiply(int a, int b) {
        // Bug: return (long)(a * b); // int * int로 overflow 후 캐스팅
        return (long) a * b; // a를 long으로 먼저 승격
    }
}
